import fitz  # PyMuPDF
import re
import os

async def replace_barcode_expand_box(input_pdf, svg_string):
    # 0. Generate Output Filename (e.g. label.pdf -> labelbar.pdf)
    base_name, ext = os.path.splitext(input_pdf)
    output_pdf = f"{base_name}bar{ext}"
    
    try:
        doc = fitz.open(input_pdf)
        page = doc[0]
        
        # Get content streams
        content_xrefs = page.get_contents()
        if isinstance(content_xrefs, int): content_xrefs = [content_xrefs]

        target_xref = -1
        original_data = b""
        
        # Header Regex: Find the "Clipping Rectangle" (the Box)
        # Looks for: [x] [y] [width] [height] re W n
        header_regex = re.compile(rb'(-?[\d\.]+)\s+(-?[\d\.]+)\s+([\d\.]+)\s+([\d\.]+)\s+re\s+W\s+n')

        # 1. Find the Stream containing the 100x30 barcode box
        print(f"Scanning {len(content_xrefs)} streams...")
        for xref in content_xrefs:
            stream_data = doc.xref_stream(xref)
            for match in header_regex.finditer(stream_data):
                w, h = float(match.group(3)), float(match.group(4))
                # Check for approx 100x30 Box
                if 99 < w < 101 and 29 < h < 31: 
                    print(f" -> Found Barcode Box in XREF {xref}")
                    target_xref = xref
                    original_data = stream_data
                    break
            if target_xref != -1: break

        if target_xref == -1:
            print("Error: Barcode header (100x30) not found.")
            return

        # -------------------------------------------------------------
        # 2. CALCULATE NEW WIDTH (The Fix)
        # -------------------------------------------------------------
        new_pdf_ops = []
        max_x_found = 0.0
        
        # Parse SVG to find the widest bar
        svg_parser = re.compile(r'M\s+([\d\.]+)\s+([\d\.]+)\s+h\s+([\d\.]+)\s+v\s+([\d\.]+)', re.IGNORECASE)
        matches = svg_parser.findall(svg_string)

        if matches:
            for x_str, y_str, w_str, h_str in matches:
                x, y = float(x_str), float(y_str)
                w, h = float(w_str), float(h_str)
                
                # Calculate the right-most edge of this bar
                current_end_x = x + w
                if current_end_x > max_x_found:
                    max_x_found = current_end_x
                
                # Convert to PDF drawing command
                op = f"{x:.4f} {y:.4f} m {(x+w):.4f} {y:.4f} l {(x+w):.4f} {(y+h):.4f} l {x:.4f} {(y+h):.4f} l h"
                new_pdf_ops.append(op)
        
        # Determine the New Box Width
        # We take the larger of: Original (100) OR New Data + 5 units Padding
        required_width = max(100.0, max_x_found + 5.0)
        
        print(f" -> Original Width: 100.0")
        print(f" -> New Data Width: {max_x_found:.2f}")
        print(f" -> EXPANDING BOX TO: {required_width:.2f}")

        # -------------------------------------------------------------
        # 3. CONSTRUCT NEW STREAM (Surgical Replacement)
        # -------------------------------------------------------------
        
        # Locate the specific header match again
        match = None
        for m in header_regex.finditer(original_data):
            if 99 < float(m.group(3)) < 101: match = m; break
        
        # DATA PART 1: Everything BEFORE the barcode box
        start_idx = match.start()
        part1 = original_data[:start_idx]
        
        # Locate the Closing 'Q' (End of the block)
        # We start searching after the header
        search_start = match.end()
        end_idx = original_data.find(b"Q", search_start)
        
        if end_idx == -1:
            print("Warning: Closing 'Q' not found. Appending to end.")
            end_idx = len(original_data)
        
        # DATA PART 3: Everything AFTER the barcode (Keep the Q!)
        # This prevents the "alignment fucked up" issue.
        part3 = original_data[end_idx:]

        # DATA PART 2: The New Barcode Block
        # We reconstruct the Header with the NEW WIDTH
        
        # A. New Header: 0 0 {WIDTH} 30 re W n
        new_header = f"0 0 {required_width:.2f} 30 re W n".encode('latin-1')
        
        # B. White Box (Eraser): Covers the new widened area
        white_box = f"\n 1 1 1 rg 0 0 {required_width:.2f} 30 re f \n"
        
        # C. New Barcode Content
        # Matrix: 1 0 0 -1 0 30 cm (Flip Y axis)
        # Color: 0 0 0 rg (Black)
        barcode_content = f"1 0 0 -1 0 30 cm 0 0 0 rg {' '.join(new_pdf_ops)} f "
        
        # Combine the new middle section
        new_middle = new_header + white_box.encode('latin-1') + barcode_content.encode('latin-1')

        # -------------------------------------------------------------
        # 4. STITCH AND SAVE
        # -------------------------------------------------------------
        final_data = part1 + new_middle + part3
        
        # Update Stream
        doc.update_stream(target_xref, final_data)
        
        # Garbage=0: Don't touch fonts, don't touch structure. Just update this object.
        doc.save(output_pdf, garbage=0, deflate=True)
        print(f"Success! Saved to: {output_pdf}")
        return output_pdf

    except Exception as e:
        print(f"Error: {e}")
        import traceback
        traceback.print_exc()
        


